external_knowledge:
; Endangered species are those that are at risk of becoming extinct due to various threats such as habitat loss or climate change; 
; High average emergence rate in this context refers to a rate greater than 0.5; 
; Mild temperatures refer to an average temperature range of 10.0 to 20.0 degrees.

sql:
SELECT population_size
FROM populations
WHERE population_id = 1;

